package com.cho2hand.marketplace.controller.trust;import com.cho2hand.marketplace.service.trust.FollowService;import jakarta.validation.constraints.Positive;import org.springframework.http.HttpStatus;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/sellers/{sellerId}") public class FollowController{private final FollowService service;public FollowController(FollowService s){service=s;}@PostMapping("/follow")@ResponseStatus(HttpStatus.NO_CONTENT)public void follow(@AuthenticationPrincipal Long user,@PathVariable @Positive Long sellerId){service.follow(user,sellerId);}@DeleteMapping("/follow")@ResponseStatus(HttpStatus.NO_CONTENT)public void unfollow(@AuthenticationPrincipal Long user,@PathVariable @Positive Long sellerId){service.unfollow(user,sellerId);}@GetMapping("/trust-score")public com.cho2hand.marketplace.dto.trust.TrustScoreResponse score(@PathVariable @Positive Long sellerId){return service.trustScore(sellerId);}}
